mapper.select:
select id
from pub
where id = #{id}

with pid as (
insert into pub_idx (name, type, serial_number) values (#{pubIdx.name}, #{pubType}, #{pubIdx.serial}) on conflict serial_number do update set name = COALESCE(#{pubIdx.name}, name) returning *
select pidx.id, pidx.name, pidx.type, pidx.serial_number, pidx.id as pub_index_id from pub_idx pidx where pidx.type = #{pubType} and
pidx.id = #{pubIdx.id}
pidx.serial_number = #{pubIdx.serial}
1=0
), ins_pub as ( insert into pub (pub_date, pub_idx_id, details) values (#{pubDate}, (select id from pid), #{pubDetails}) returning * ) select p.id, pi.name, pi.type, p.details || jsonb_build_object('@type', pi.type::text) as details, p.pub_date, pi.serial_number from ins_pub p inner join pid pi on p.pub_idx_id = pi.id

and p.id = #{criteria.id}
and exists(select * from transcription t where t.pub_id = p.id)
and (name ~* #{criteria.searchName} or coalesce(details->>'issueName', details->>'edition') ~* #{criteria.searchName})
and pi.type = #{criteria.type}::pub_type
p.pub_date >= #{criteria.dateStart}
and p.pub_date <= #{criteria.dateEnd}
order by p.pub_date nulls first, pi.name, p.details->>'volume' nulls first, p.details->>'issue' nulls first, p.details->>'issueName' nulls first, p.details->>'edition' nulls first, p.id
